18.     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
19.     .Append(mlContext.Transforms.Concatenate("Features",
20.         nameof(CustomerData.Age),
21.         nameof(CustomerData.Income),
22.         "RegionEncoded",
23.         nameof(CustomerData.PurchaseHistory)))
24.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
25.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
26.         labelColumnName: "Label",
27.         featureColumnName: "Features"));
28. 
29. // Split with stratification on the label to ensure both classes appear in test set
30. var labeledData = mlContext.Transforms.Conversion.MapValue(
31.         "StratifyColumn", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
32.         inputColumnName: nameof(CustomerData.Churned))
33.     .Fit(dataView).Transform(dataView);
34. var split = mlContext.Data.TrainTestSplit(labeledData, testFraction: 0.2,
35.     samplingKeyColumnName: "StratifyColumn");
36. 
