 using Microsoft.ML;
 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;
 using ChurnPredictor.Models;

 var builder = WebApplication.CreateBuilder(args);

 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

 // Load data — Churned is "Yes"/"No" so load as string then map to bool
 var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

 // Build full pipeline: label mapping → feature engineering → trainer
 var pipeline = mlContext.Transforms.Conversion.MapValue(
         "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
         inputColumnName: nameof(CustomerData.Churned))
     .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(CustomerData.Age),
         nameof(CustomerData.Income),
         "RegionEncoded",
         nameof(CustomerData.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label",
         featureColumnName: "Features"));

 // Cross-validate (better than train/test split for small datasets)
 var cvResults = mlContext.BinaryClassification.CrossValidate(dataView, pipeline,
     numberOfFolds: 5, labelColumnName: "Label");
 var avgAccuracy = cvResults.Average(r => r.Metrics.Accuracy);
 var avgAuc = cvResults.Average(r => r.Metrics.AreaUnderRocCurve);
 var avgF1 = cvResults.Average(r => r.Metrics.F1Score);
 Console.WriteLine($"Cross-validated metrics (5-fold):");
 Console.WriteLine($"  Accuracy: {avgAccuracy:F4}");
 Console.WriteLine($"  AUC:      {avgAuc:F4}");
 Console.WriteLine($"  F1 Score: {avgF1:F4}");

 // Re-train on full dataset and save
 var fullModel = pipeline.Fit(dataView);
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
 mlContext.Model.Save(fullModel, dataView.Schema, modelPath);

 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerInput input) =>
 {
     var customerData = new CustomerData
     {
         Age = input.Age,
         Income = input.Income,
         Region = input.Region,
         PurchaseHistory = input.PurchaseHistory
     };
     var prediction = pool.Predict(customerData);
     return Results.Ok(new
     {
         WillChurn = prediction.PredictedLabel,
         Probability = prediction.Probability
     });
 });

 app.Run();

 namespace ChurnPredictor.Models
 {
     public class CustomerData
     {
         [LoadColumn(0)] public float Age { get; set; }
         [LoadColumn(1)] public float Income { get; set; }
         [LoadColumn(2)] public string Region { get; set; } = string.Empty;
         [LoadColumn(3)] public float PurchaseHistory { get; set; }
         [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
     }

     public class CustomerInput
     {
         public float Age { get; set; }
         public float Income { get; set; }
         public string Region { get; set; } = string.Empty;
         public float PurchaseHistory { get; set; }
     }

     public class ChurnPrediction
     {
         [ColumnName("PredictedLabel")]
         public bool PredictedLabel { get; set; }
         public float Probability { get; set; }
     }
 }

